// Custom Hook for Theme
function useTheme() {
  const [themeColor, setThemeColor] = useState(localStorage.getItem('themeColor') || '#5865F2');
  useEffect(() => { localStorage.setItem('themeColor', themeColor); }, [themeColor]);
  return [themeColor, setThemeColor];
}

function App() {
  const [user] = useAuthState(auth);
  const [currentChannel, setCurrentChannel] = useState({ id: 'general', name: 'general' });
  const [themeColor, setThemeColor] = useTheme();

  return (
    <div className="App" style={{'--accent-color': themeColor}}>
      {user ? <ChatRoom channel={currentChannel} setChannel={setCurrentChannel} themeColor={themeColor} setThemeColor={setThemeColor} /> : <AuthScreen themeColor={themeColor} />}
    </div>
  );
}

function AuthScreen({ themeColor }) {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleEmailAuth = async (e) => {
    e.preventDefault();
    setError('');
    try {
      if (isLogin) {
        await auth.signInWithEmailAndPassword(email, password);
      } else {
        await auth.createUserWithEmailAndPassword(email, password);
      }
    } catch (err) { setError(err.message); }
  };

  const signInWithGoogle = () => {
    const provider = new firebase.auth.GoogleAuthProvider();
    auth.signInWithPopup(provider);
  };

  return (
    <div className="signin-container">
      <div style={{background: '#2f3136', padding: '32px', borderRadius: '12px', width: '320px', boxShadow: '0 8px 24px rgba(0,0,0,0.2)'}}>
        <h2 style={{marginTop: 0, textAlign: 'center', color: '#fff'}}>{isLogin ? 'Welcome Back' : 'Create an Account'}</h2>
        <form onSubmit={handleEmailAuth} style={{display: 'flex', flexDirection: 'column', gap: '16px', padding: 0, background: 'transparent'}}>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <button type="submit" className="sign-in" style={{display: 'block', backgroundColor: themeColor}}>{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#ed4245', fontSize: '13px', textAlign: 'center'}}>{error}</p>}
        <p style={{textAlign: 'center', fontSize: '14px', cursor: 'pointer', color: themeColor, marginTop: '16px'}} onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Need an account? Register' : 'Already have an account? Login'}
        </p>
        <hr style={{borderColor: '#202225', margin: '24px 0'}} />
        <button className="sign-in" style={{width: '100%', backgroundColor: '#fff', color: '#000'}} onClick={signInWithGoogle}>Continue with Google</button>
      </div>
    </div>
  );
}

function SettingsModal({ close, themeColor, setThemeColor }) {
  const [name, setName] = useState(auth.currentUser.displayName || '');
  const [photo, setPhoto] = useState(auth.currentUser.photoURL || '');
  const colors = ['#5865F2', '#ed4245', '#3ba55c', '#fee75c', '#eb459e', '#9b59b6'];

  const saveSettings = async () => {
    await auth.currentUser.updateProfile({ displayName: name, photoURL: photo });
    close();
  };

  return (
    <div className="settings-overlay">
      <div className="settings-layout">
        <div className="settings-sidebar">
          <div className="settings-nav">
            <h4>User Settings</h4>
            <div className="settings-tab active">My Account</div>
            <div className="settings-divider"></div>
            <div className="settings-tab logout" onClick={() => auth.signOut()}>Log Out</div>
          </div>
        </div>
        <div className="settings-content">
          <button className="close-settings" onClick={close}>X</button>
          <h2>My Account</h2>
          <div className="settings-card">
            <div>
              <img src={photo || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="Preview" className="settings-avatar-preview" />
            </div>
            <div className="settings-group">
              <label>DISPLAY NAME</label>
              <input placeholder="Enter a new name" value={name} onChange={(e) => setName(e.target.value)} style={{borderColor: themeColor}} />
            </div>
            <div className="settings-group">
              <label>AVATAR URL</label>
              <input placeholder="https://..." value={photo} onChange={(e) => setPhoto(e.target.value)} style={{borderColor: themeColor}} />
            </div>
            <div className="settings-group">
              <label>APP THEME COLOR</label>
              <div className="color-picker">
                {colors.map(c => (
                  <div key={c} className="color-swatch" style={{backgroundColor: c, borderColor: themeColor === c ? '#fff' : 'transparent'}} onClick={() => setThemeColor(c)} />
                ))}
              </div>
            </div>
          </div>
          <button className="save-btn" onClick={saveSettings} style={{backgroundColor: themeColor, borderRadius: '8px', border: 'none'}}>Save Changes</button>
        </div>
      </div>
    </div>
  );
}

function ChatRoom({ channel, setChannel, themeColor, setThemeColor }) {
  const dummy = useRef();
  const [showSettings, setShowSettings] = useState(false);
  const [formValue, setFormValue] = useState('');
  const [imgUrlForm, setImgUrlForm] = useState('');
  const [showLinkInput, setShowLinkInput] = useState(false);
  
  // SOFT RATELIMIT STATE
  const [cooldown, setCooldown] = useState(0);

  const isAdmin = auth.currentUser?.email === 'vincentr111222@gmail.com';
  const channelsRef = firestore.collection('channels');
  const [channels] = useCollectionData(channelsRef.orderBy('createdAt'), { idField: 'id' });
  const messagesRef = firestore.collection(`messages_${channel.id}`);
  const query = messagesRef.orderBy('createdAt').limit(50);
  const [messages] = useCollectionData(query, { idField: 'id' });

  useEffect(() => {
    if (channels && channels.length === 0 && isAdmin) {
      channelsRef.add({ name: 'general', createdAt: firebase.firestore.FieldValue.serverTimestamp() });
    }
    if (channels && channels.length > 0 && channel.id === 'general' && !channels.find(c => c.name === 'general')) {
      setChannel(channels[0]);
    }
  }, [channels, isAdmin, setChannel, channelsRef, channel.id]);

  // Handle Cooldown Timer
  useEffect(() => {
    let timer;
    if (cooldown > 0) {
      timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [cooldown]);

  const addChannel = async () => {
    const name = prompt("Enter new channel name:");
    if (name) {
      await channelsRef.add({ name: name.toLowerCase().replace(/\s+/g, '-'), createdAt: firebase.firestore.FieldValue.serverTimestamp() });
    }
  };

  const deleteChannel = async (e, id) => {
    e.stopPropagation();
    if (window.confirm("Delete this channel?")) {
      await channelsRef.doc(id).delete();
      if (channel.id === id) setChannel({id: 'general', name: 'general'}); 
    }
  };

  const sendMessage = async (e) => {
    e.preventDefault();
    if ((!formValue.trim() && !imgUrlForm.trim()) || cooldown > 0) return;
    
    const { uid, photoURL, displayName, email } = auth.currentUser;

    await messagesRef.add({
      text: formValue,
      imgUrl: imgUrlForm.trim() || null,
      createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      uid,
      email: email || '',
      photoURL: photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png',
      displayName: displayName || email?.split('@')[0] || 'Anonymous'
    });

    setFormValue('');
    setImgUrlForm('');
    setShowLinkInput(false);
    setCooldown(3); // 3 SECOND RATELIMIT
    dummy.current.scrollIntoView({ behavior: 'smooth' });
  }

  return (
    <div className="discord-layout">
      {showSettings && <SettingsModal close={() => setShowSettings(false)} themeColor={themeColor} setThemeColor={setThemeColor} />}
      <div className="sidebar">
        <div className="server-icon active" style={{backgroundColor: themeColor}}>TK</div>
      </div>
      
      <div className="channels">
        <div className="channels-header">
          <h3>Text Channels</h3>
          {isAdmin && <button className="add-btn" onClick={addChannel}>+</button>}
        </div>
        
        <div className="channel-list">
          {channels && channels.map(c => (
            <div key={c.id} className={`channel ${channel.id === c.id ? 'active' : ''}`} onClick={() => setChannel(c)}>
              <span className="channel-name"><span className="hash-icon">#</span> {c.name}</span>
              {isAdmin && <button className="del-btn" onClick={(e) => deleteChannel(e, c.id)}>X</button>}
            </div>
          ))}
        </div>
        
        <div className="user-panel">
          <div className="user-panel-info">
            <img src={auth.currentUser?.photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="PFP" />
            <div>
              <strong>{auth.currentUser?.displayName || auth.currentUser?.email?.split('@')[0]}</strong>
              <span>Online</span>
            </div>
          </div>
          <button className="settings-btn" onClick={() => setShowSettings(true)} style={{color: showSettings ? themeColor : ''}}>⚙️</button>
        </div>
      </div>

      <div className="chat-container">
        <header>
          <div className="header-title"><span className="hash-icon">#</span> {channel.name}</div>
        </header>

        <main>
          {messages && messages.map(msg => (
            <ChatMessage key={msg.id} message={msg} currentUserUid={auth.currentUser.uid} isAdmin={isAdmin} onDelete={() => messagesRef.doc(msg.id).delete()} />
          ))}
          <span ref={dummy}></span>
        </main>

        <div className="form-wrapper">
          {showLinkInput && (
            <div className="url-input-container">
              <input type="text" placeholder="Paste Image URL" value={imgUrlForm} onChange={(e) => setImgUrlForm(e.target.value)} />
            </div>
          )}
          <form onSubmit={sendMessage}>
            <button type="button" className={`link-btn ${showLinkInput ? 'active' : ''}`} onClick={() => setShowLinkInput(!showLinkInput)} style={{color: showLinkInput ? themeColor : ''}}>🔗</button>
            <input 
              type="text" 
              value={cooldown > 0 ? `Slowmode is active. Wait ${cooldown}s...` : formValue} 
              onChange={(e) => setFormValue(e.target.value)} 
              placeholder={`Message #${channel.name}`} 
              disabled={cooldown > 0}
              style={{opacity: cooldown > 0 ? 0.5 : 1}}
            />
            <button type="submit" style={{display: 'none'}}></button>
          </form>
        </div>
      </div>
    </div>
  )
}

function ChatMessage({ message, currentUserUid, isAdmin, onDelete }) {
  const { text, imgUrl, photoURL, displayName, uid } = message;
  const canDelete = uid === currentUserUid || isAdmin;

  return (
    <div className="message" style={{justifyContent: 'space-between'}}>
      <div style={{display: 'flex'}}>
        <img className="message-avatar" src={photoURL} alt="user" />
        <div className="message-content">
          <span className="msg-author">{displayName}</span>
          {text && <p>{text}</p>}
          {imgUrl && <img src={imgUrl} className="msg-img" alt="attachment" onClick={() => window.open(imgUrl, '_blank')} />}
        </div>
      </div>
      {canDelete && <button onClick={onDelete} style={{background: 'transparent', border: 'none', color: '#ed4245', cursor: 'pointer', opacity: 0.7}}>Del</button>}
    </div>
  )
}
export default App;
